                      "code": "1512",
                      "system": "https://duodecim.fi/fhir/stu3/CodeSystem/questionnaire-option-83-live"
                    }
                  }
                ]
              },
              {
                "linkId": "404",
                "text": "Tuntuuko oireilu siltä, että olkapää voisi mennä sijoiltaan tai onko olkapää aiemmin mennyt sijoiltaan?",
                "answer": [
                  {
                    "valueBoolean": false
                  }
                ]
              },
              {
                "linkId": "398",
                "text": "Ovatko olkavarren aktiiviset (itse liikutetut) liikkeet, varsinkin sivusuuntaan, kivuliaita ja rajoittuneita?",
                "answer": [
                  {
                    "valueBoolean": false
                  }
                ]
              },
              {
                "linkId": "399",
                "text": "Onko olkapään passiivinen liikelaajuus (joku toinen liikuttaa olkavartta tai olkavartta liikutetaan toisella kädellä) selvästi laajempi kuin aktiivinen liikelaajuus?"
              },
              {
                "linkId": "406",
                "text": "Onko olkavarren lihasvoima heikentynyt verrattuna terveeseen käteen ja onko käsi helpointa nostaa ylös etukautta?"
              },
              {
                "linkId": "4705",
                "text": "<p>Jos sinulla ei ole tiedossa esteitä kipulääkkeiden käytölle, voit kokeilla hoitaa kipuasi turvallisesti kotona tulehduskipulääkkeillä ja parasetamolilla. Esimerkiksi ibuprofeenin (esim. Burana) turvallinen itsehoito-annos on 200 mg 1-2 tablettia kerrallaan 1-3 kertaa päivässä. Parasetamolin (esim. Panadol) turvallinen itsehoito-annos on 1 g 1-3 kertaa päivässä. Näiden kipulääkkeiden vaikutus alkaa näkyä yleensä n. 30 minuutin kuluttua lääkkeiden otosta. Voimakkaammassa kivussa kannatta ottaa sekä tulehduskipulääkettä että parasetamolia yhtä aikaa.</p>\n<p>Kivun hoidossa itsehoitolääkkeet on tarkoitettu tilapäisten oireiden hoitoon ja satunnaiseen, kerrallaan korkeintaan muutaman päivän jatkuvaan käyttöön. Voit lukea lisää kipulääkkeiden käytöstä <a href=\"https://www.terveyskirjasto.fi/dlk00649\" target=\"_blank\" rel=\"nofollow noopener noreferrer\">Terveyskirjaston</a> artikkelista.</p>"
              },
              {
                "linkId": "5",
                "text": "Miten voimakasta kipua sinulla on ollut viimeisen vuorokauden aikana?",
